import * as React from 'react';
import { styled } from '@mui/material/styles';
import Box from '@mui/material/Box';
import Paper from '@mui/material/Paper';
import Chip from '@mui/material/Chip';
import Grid from '@mui/material/Grid';
import Card from '@mui/material/Card';
import CardContent from '@mui/material/CardContent';
import Typography from '@mui/material/Typography';
import Divider from '@mui/material/Divider';

const Item = styled(Paper)(({ theme }) => ({
  backgroundColor: theme.palette.mode === 'dark' ? '#1A2027' : '#fff',
  ...theme.typography.body2,
  padding: theme.spacing(2),
  textAlign: 'center',
  color: theme.palette.text.secondary,
}));

export default class PortfolioDashboard extends React.Component {
  handleChipClick = () => {
    console.log('My Portfolio chip clicked');
  };

  render() {
    return (
      <Box sx={{ flexGrow: 1, padding: 3 }}>
        {/* Navigation Bar */}
        <Paper elevation={3} sx={{ padding: 2, display: 'flex', justifyContent: 'center' }}>
          <Chip label="My Portfolio" color="primary" onClick={this.handleChipClick} />
        </Paper>

        <Grid container spacing={2} sx={{ marginTop: 2 }}>
          <Grid item xs={12} md={6}>
            <Card>
              <CardContent>
                <Typography variant="h5" component="div">
                  About Me
                </Typography>
                <Divider sx={{ marginY: 1 }} />
                <Typography variant="body2" color="text.secondary">
                  Welcome to my portfolio! I am a passionate web developer with expertise in React, JavaScript, and frontend technologies.
                </Typography>
              </CardContent>
            </Card>
          </Grid>

          <Grid item xs={12} md={6}>
            <Card>
              <CardContent>
                <Typography variant="h5" component="div">
                  Skills
                </Typography>
                <Divider sx={{ marginY: 1 }} />
                <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                  <Chip label="React" color="secondary" />
                  <Chip label="JavaScript" color="secondary" />
                  <Chip label="TypeScript" color="secondary" />
                  <Chip label="Node.js" color="secondary" />
                </Box>
              </CardContent>
            </Card>
          </Grid>
        </Grid>
      </Box>
    );
  }
}
